import re
def norm_name(n):
    n = ' '.join(n.strip().casefold().split())
    return re.sub(r'[^\w\s]', '', n, flags=re.UNICODE)
print(norm_name('  José  Pérez '))

import re
def norm_doc(d):
    return re.sub(r'\D', '', d or '')
def er_score(a, b):
    if norm_doc(a.get('doc')) and norm_doc(a.get('doc')) == norm_doc(b.get('doc')):
        if a.get('bk') == b.get('bk'):
            return 1.0
        return 0.8
    if a.get('bk') == b.get('bk'):
        return 0.5
    return 0.0
print(er_score({'doc': '12345678', 'bk': 'q|a|lima'}, {'doc': '12345678', 'bk': 'q|a|lima'}))
print(er_score({'doc': '', 'bk': 'x'}, {'doc': '', 'bk': 'y'}))

