def rel_score(km, surname_jaccard):
    geo = 0.0 if km is None else max(0.0, 1.0 - min(km, 50) / 50)
    return round(0.5 * geo + 0.5 * (surname_jaccard or 0.0), 3)
print(rel_score(1.2, 0.5))
print(rel_score(None, 0.0))

txs = [('A', 'D', 1), ('C', 'D', 1), ('A', 'E', 1), ('C', 'F', 1)]
def neighbors(txs, node):
    s = set()
    for x, y, _ in txs:
        if x == node:
            s.add(y)
        if y == node:
            s.add(x)
    return s
print(sorted(neighbors(txs, 'A') & neighbors(txs, 'C')))

def uncertainty_band(missing, conflict):
    if conflict:
        return 'high'
    if missing:
        return 'medium'
    return 'low'
print(uncertainty_band(['email'], False), uncertainty_band([], True))

