from math import isfinite
th = {'accept_min': 0.8, 'review_low': 0.4}
def decide_ops_status(score, high_signal=False):
    if score is None or not isfinite(score) or not (0 <= score <= 1):
        return 'invalid_input'
    if high_signal:
        return 'needs_review'
    if score < th['review_low']:
        return 'abstain'
    if score < th['accept_min']:
        return 'needs_review'
    return 'needs_review'  # high score still human review in S13
for s in [None, 0.2, 0.5, 0.9]:
    print(s, decide_ops_status(s))
print('high_signal', decide_ops_status(0.3, high_signal=True))

